#include <mpi.h>
#include <omp.h>
#include <vector>
#include <cmath>
#include <algorithm>

struct Point {
    double x, y;
};

double distance(Point const& p1, Point const& p2) {
    return std::sqrt(std::pow(p2.x - p1.x, 2) + std::pow(p2.y - p1.y, 2));
}

double closestPair(std::vector<Point> const& points) {
    int rank, size;
    MPI_Comm_rank(MPI_COMM_WORLD, &rank);
    MPI_Comm_size(MPI_COMM_WORLD, &size);

    // Distribute points evenly among ranks
    std::vector<Point> local_points(points.size() / size + (rank < points.size() % size));
    for (int i = 0; i < local_points.size(); ++i) {
        int global_index = rank * (points.size() / size) + i;
        if (global_index >= points.size()) break;
        local_points[i] = points[global_index];
    }

    // Find the closest pair within each rank using OpenMP
    double min_dist = DBL_MAX;
    #pragma omp parallel for reduction(min: min_dist)
    for (int i = 0; i < local_points.size(); ++i) {
        for (int j = i + 1; j < local_points.size(); ++j) {
            double dist = distance(local_points[i], local_points[j]);
            if (dist < min_dist) min_dist = dist;
        }
    }

    // Gather the minimum distances from all ranks and find the global minimum
    std::vector<double> min_dists(size);
    MPI_Gather(&min_dist, 1, MPI_DOUBLE, &min_dists[0], 1, MPI_DOUBLE, 0, MPI_COMM_WORLD);

    double result = DBL_MAX;
    if (rank == 0) {
        for (int i = 0; i < size; ++i) {
            if (min_dists[i] < result) result = min_dists[i];
        }
    }

    // Broadcast the final result to all ranks
    MPI_Bcast(&result, 1, MPI_DOUBLE, 0, MPI_COMM_WORLD);

    return result;
}
